mapper.select:
(
SELECT prj_id as id,prj_cd,prj_nm,par_cd,par_nm, is_leaf as leaf,'1' as to_add  FROM ${dataIntegration}.VIEW_HSP_PROJECT
MINUS
SELECT prj_id as id,prj_cd,prj_nm,par_cd,par_nm,leaf,'1' as to_add FROM project_control_r where year = #{year}
)
union
(
SELECT prj_id as id,prj_cd,prj_nm,par_cd,par_nm,leaf,'2' as to_add  FROM project_control_r where year = #{year}
MINUS
SELECT prj_id as id,prj_cd,prj_nm,par_cd,par_nm,is_leaf as leaf,'2' as to_add  FROM ${dataIntegration}.VIEW_HSP_PROJECT
)

mapper.update:
MERGE INTO project_control_r t USING (
SELECT #{item.prjId} AS prj_id, #{item.prjCd} AS prj_cd, #{item.prjNm} AS prj_nm, #{item.parCd} AS par_cd, #{item.parNm} AS par_nm, #{item.leaf} AS leaf, #{year} AS year FROM DUAL
) s ON (t.prj_id = s.prj_id AND t.year = s.year) WHEN MATCHED THEN UPDATE SET t.prj_cd = s.prj_cd, t.prj_nm = s.prj_nm, t.par_cd = s.par_cd, t.par_nm = s.par_nm, t.leaf = s.leaf
